```c
for (loopcounter = 0;; loopcounter++) {
    if (chip->polling_mode || do_poll) {
        spin_lock_irq(&chip->reg_lock);
        azx_update_rirb(chip);
        spin_unlock_irq(&chip->reg_lock);
