2483: /* trigger power-save check at writing parameter */
2484: static int param_set_xint(const char *val, const struct kernel_param *kp)
2485: {
2486: 	struct azx *chip;
2487: 	struct hda_codec *c;
2488: 	int prev = power_save;
2489: 	int ret = param_set_int(val, kp);
2490: 
2491: 	if (ret || prev == power_save)
2492: 		return ret;
2493: 
2494: 	mutex_lock(&card_list_lock);
2495: 	list_for_each_entry(chip, &card_list, list) {
2496: 		if (!chip->bus || chip->disabled)
2497: 			continue;
2498: 		list_for_each_entry(c, &chip->bus->codec_list, list)
2499: 			snd_hda_power_sync(c);
2500: 	}
2501: 	mutex_unlock(&card_list_lock);
2502: 	return 0;
2503: }
2504: #else
2505: #define azx_add_card_list(chip) /* NOP */
2506: #define azx_del_card_list(chip) /* NOP */
2507: #endif /* CONFIG_PM */
2508: 
2509: #if defined(CONFIG_PM_SLEEP) || defined(SUPPORT_VGA_SWITCHEROO)
2510: /*
2511:  * power management
2512:  */
2513: static int azx_suspend(struct device *dev)
2514: {
2515: 	struct pci_dev *pci = to_pci_dev(dev);
2516: 	struct snd_card *card = dev_get_drvdata(dev);
2517: 	struct azx *chip = card->private_data;
2518: 	struct azx_pcm *p;
2519: 
2520: 	snd_power_change_state(card, SNDRV_CTL_POWER_D3hot);
2521: 	azx_clear_irq_pending(chip);
2522: 	list_for_each_entry(p, &chip->pcm_list, list)
2523: 		snd_pcm_suspend_all(p->pcm);
2524: 	if (chip->initialized)
2525: 		snd_hda_suspend(chip->bus);
2526: 	azx_stop_chip(chip);
2527: 	if (chip->irq >= 0) {
2528: 		free_irq(chip->irq, chip);
2529: 		chip->irq = -1;
2530: 	}
2531: 	if (chip->msi)
2532: 		pci_disable_msi(chip->pci);
2533: 	pci_disable_device(pci);
2534: 	pci_save_state(pci);
2535: 	pci_set_power_state(pci, PCI_D3hot);
2536: 	return 0;
2537: }
2538: 
2539: static int azx_resume(struct device *dev)
2540: {
2541: 	struct pci_dev *pci = to_pci_dev(dev);
2542: 	struct snd_card *card = dev_get_drvdata(dev);
2543: 	struct azx *chip = card->private_data;
2544: 
2545: 	pci_set_power_state(pci, PCI_D0);
2546: 	pci_restore_state(pci);
2547: 	if (pci_enable_device(pci) < 0) {
2548: 		printk(KERN_ERR "hda-intel: pci_enable_device failed, "
2549: 		       "disabling device\n");
2550: 		snd_card_disconnect(card);
2551: 		return -EIO;
2552: 	}
2553: 	pci_set_master(pci);
2554: 	if (chip->msi)
2555: 		if (pci_enable_msi(pci) < 0)
2556: 			chip->msi = 0;
2557: 	if (azx_acquire_irq(chip, 1) < 0)
2558: 		return -EIO;
2559: 	azx_init_pci(chip);
2560: 
2561: 	azx_init_chip(chip, 1);
2562: 
2563: 	snd_hda_resume(chip->bus);
2564: 	snd_power_change_state(card, SNDRV_CTL_POWER_D0);
2565: 	return 0;
2566: }
2567: #endif /* CONFIG_PM_SLEEP || SUPPORT_VGA_SWITCHEROO */
2568: 
2569: #ifdef CONFIG_PM_RUNTIME
2570: static int azx_runtime_suspend(struct device *dev)
2571: {
2572: 	struct snd_card *card = dev_get_drvdata(dev);
2573: 	struct azx *chip = card->private_data;
2574: 
2575: 	azx_stop_chip(chip);
2576: 	azx_clear_irq_pending(chip);
2577: 	return 0;
2578: }
2579: 
2580: static int azx_runtime_resume(struct device *dev)
2581: {
2582: 	struct snd_card *card = dev_get_drvdata(dev);
2583: 	struct azx *chip = card->private_data;
2584: 
2585: 	azx_init_pci(chip);
2586: 	azx_init_chip(chip, 1);
2587: 	return 0;
2588: }
2589: 
2590: static int azx_runtime_idle(struct device *dev)
2591: {
2592: 	struct snd_card *card = dev_get_drvdata(dev);
2593: 	struct azx *chip = card->private_data;
2594: 
2595: 	if (!power_save_controller ||
2596: 	    !(chip->driver_caps & AZX_DCAPS_PM_RUNTIME))
2597: 		return -EBUSY;
2598: 
2599: 	return 0;
2600: }
2601: 
2602: #endif /* CONFIG_PM_RUNTIME */
2603: 
2604: #ifdef CONFIG_PM
2605: static const struct dev_pm_ops azx_pm = {
2606: 	SET_SYSTEM_SLEEP_PM_OPS(azx_suspend, azx_resume)
2607: 	SET_RUNTIME_PM_OPS(azx_runtime_suspend, azx_runtime_resume, azx_runtime_idle)
2608: };
2609: 
2610: #define AZX_PM_OPS	&azx_pm
