1232: /*
1233:  * initialize the PCI registers
1234:  */
1235: /* update bits in a PCI register byte */
1236: static void update_pci_byte(struct pci_dev *pci, unsigned int reg,
1237: 			    unsigned char mask, unsigned char val)
1238: {
1239: 	unsigned char data;
1240: 
1241: 	pci_read_config_byte(pci, reg, &data);
1242: 	data &= ~mask;
1243: 	data |= (val & mask);
1244: 	pci_write_config_byte(pci, reg, data);
1245: }
